private void xrTableCell44_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     decimal OpenStockReceivingHall = 0;
    decimal FarmIntake = 0;
    decimal HatcheryIntake = 0;
    decimal RejCracks = 0;
    decimal RejWhole = 0;
    decimal RejBroken = 0;
    decimal RejOther = 0;
    decimal SellToLogistic = 0;
    decimal SellOfHatEggs = 0;
    decimal EggsToCollage = 0;
    decimal TransToHatchery = 0;
    decimal SettedEggs = 0;
    decimal St_RejCrack = 0;
    decimal St_RejWhole = 0;
    decimal St_RejBroken = 0;
    decimal St_RejOther = 0;
    decimal EggsToOffal = 0;

    if (GetCurrentColumnValue("OpenStockReceivingHall") != null)
        OpenStockReceivingHall = Convert.ToDecimal(GetCurrentColumnValue("OpenStockReceivingHall"));

    if (GetCurrentColumnValue("FarmIntake") != null)
        FarmIntake = Convert.ToDecimal(GetCurrentColumnValue("FarmIntake"));

    if (GetCurrentColumnValue("HatcheryIntake") != null)
        HatcheryIntake = Convert.ToDecimal(GetCurrentColumnValue("HatcheryIntake"));

    if (GetCurrentColumnValue("RejCracks") != null)
        RejCracks = Convert.ToDecimal(GetCurrentColumnValue("RejCracks"));

    if (GetCurrentColumnValue("RejWhole") != null)
        RejWhole = Convert.ToDecimal(GetCurrentColumnValue("RejWhole"));

    if (GetCurrentColumnValue("RejBroken") != null)
        RejBroken = Convert.ToDecimal(GetCurrentColumnValue("RejBroken"));

    if (GetCurrentColumnValue("RejOther") != null)
        RejOther = Convert.ToDecimal(GetCurrentColumnValue("RejOther"));

    if (GetCurrentColumnValue("SellToLogistic") != null)
        SellToLogistic = Convert.ToDecimal(GetCurrentColumnValue("SellToLogistic"));

    if (GetCurrentColumnValue("SellOfHatEggs") != null)
        SellOfHatEggs = Convert.ToDecimal(GetCurrentColumnValue("SellOfHatEggs"));

    if (GetCurrentColumnValue("EggsToCollage") != null)
        EggsToCollage = Convert.ToDecimal(GetCurrentColumnValue("EggsToCollage"));

    if (GetCurrentColumnValue("TransToHatchery") != null)
        TransToHatchery = Convert.ToDecimal(GetCurrentColumnValue("TransToHatchery"));

    if (GetCurrentColumnValue("SettedEggs") != null)
        SettedEggs = Convert.ToDecimal(GetCurrentColumnValue("SettedEggs"));

    if (GetCurrentColumnValue("St_RejCrack") != null)
        St_RejCrack = Convert.ToDecimal(GetCurrentColumnValue("St_RejCrack"));

    if (GetCurrentColumnValue("St_RejWhole") != null)
        St_RejWhole = Convert.ToDecimal(GetCurrentColumnValue("St_RejWhole"));

    if (GetCurrentColumnValue("St_RejBroken") != null)
        St_RejBroken = Convert.ToDecimal(GetCurrentColumnValue("St_RejBroken"));

    if (GetCurrentColumnValue("St_RejOther") != null)
        St_RejOther = Convert.ToDecimal(GetCurrentColumnValue("St_RejOther"));

    if (GetCurrentColumnValue("EggsToOffal") != null)
        EggsToOffal = Convert.ToDecimal(GetCurrentColumnValue("EggsToOffal"));

    // Apply the equation
    decimal result =
        OpenStockReceivingHall +
        FarmIntake +
        HatcheryIntake -
        RejCracks -
        RejWhole -
        RejBroken -
        RejOther -
        SellToLogistic -
        SellOfHatEggs -
        EggsToCollage -
        TransToHatchery -
        SettedEggs -
        St_RejCrack -
        St_RejWhole -
        St_RejBroken -
        St_RejOther -
        EggsToOffal;

    // If you want to accumulate for totals later:
    TotalStock += result;

    XRTableCell cell = sender as XRTableCell;
    cell.Text = result.ToString("0"); // no decimals, adjust as needed
}


